/**
 * Get the client IP address from the request.
 *
 * Always use the real socket address; never trust X-Forwarded-For.
 * Trusting client-supplied headers allows attackers to rotate IPs
 * and bypass rate limiting entirely.
 */
getClientIp(req: http.IncomingMessage): string {
  // Use the actual TCP connection's remote address, ignoring any headers
  return req.socket.remoteAddress || '127.0.0.1';
}

/**
 * Check if a request from the given IP is allowed.
 */
all
